import{_ as e,c as p,o as t,ag as r}from"./chunks/framework.ELrfyV9R.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/aehyok/status/2043497618790285624","created":"2026-04-13T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/Claude 账号重启，看看这样准备还有机会通关吗？.md","filePath":"ai/bookmark/Claude 账号重启，看看这样准备还有机会通关吗？.md","lastUpdated":1776858534000}'),o={name:"ai/bookmark/Claude 账号重启，看看这样准备还有机会通关吗？.md"};function s(i,a,l,m,g,n){return t(),p("div",null,a[0]||(a[0]=[r('<p><img src="https://pbs.twimg.com/media/HFveekYbAAABSNK?format=jpg&amp;name=large" alt="图像"></p><p>前两天连龙虾之父的账号都被封了，但是很快就解封了，这事你说神奇不神奇。A社的确是算力紧张，加上中转站撸毛严重，再加上最近新模型Mythos的造势，可谓是对我们小用户杀红了眼，形成了漂亮国新一层的斩杀线。</p><p><img src="https://pbs.twimg.com/media/HFr97GzbkAAVzbE?format=jpg&amp;name=large" alt="图像"></p><h2 id="一、-什么情况下会被封号" tabindex="-1">一、 什么情况下会被封号？ <a class="header-anchor" href="#一、-什么情况下会被封号" aria-label="Permalink to &quot;一、 什么情况下会被封号？&quot;">​</a></h2><p>1、自建VPS会被封、静态住宅IP会被封、万人骑机场会被封</p><p>2、解码平台会被封、实体国外手机卡会被封</p><p>3、虚拟卡支付会被封、Apple Pay会被封、Google Pay会被封、实体卡支付会被封</p><p>Peter被封我觉得以上因素应该都不是了吧，主要可能就是日常额度用量实在太猛了，触发了超限。但是我也看到了万人骑同样还能“逍遥法外”，虚拟银行卡我朋友最近刚开了两个，同样的手段一台电脑可以，一台电脑不行。所以我也想再次重开账号试试。</p><p>由于我主流浏览器都已经被我用过了，于是这次选择了一个专门的指纹浏览器再来试试看。</p><p>整体准备如下</p><p>A、网络环境：<strong>VPS + 住宅 IP</strong></p><p><strong>B、浏览器：指纹浏览器AdsPower</strong></p><p>C、注册邮箱+接码平台：使用Cloudflare绑定域名免费邮箱</p><p>D、支付：Bitget银行卡+Apple Pay或者Google Pay</p><h2 id="二、-网络环境-vps-住宅ip" tabindex="-1">二、 网络环境：VPS + 住宅IP <a class="header-anchor" href="#二、-网络环境-vps-住宅ip" aria-label="Permalink to &quot;二、 网络环境：VPS + 住宅IP&quot;">​</a></h2><p>网络环境我就不多说了，这个配置应该有超级多的人在用。</p><h2 id="三、浏览器-指纹浏览器adspower" tabindex="-1">三、浏览器：指纹浏览器AdsPower <a class="header-anchor" href="#三、浏览器-指纹浏览器adspower" aria-label="Permalink to &quot;三、浏览器：指纹浏览器AdsPower&quot;">​</a></h2><p>先来简单介绍一下，AdsPower 是一款<strong>反检测（Anti-detect）浏览器</strong>，核心优势可以概括为以下几点：</p><ol><li><strong>指纹伪装</strong>：为每个账号生成独立的浏览器指纹，有效防止平台检测和封号。</li><li><strong>多账号管理</strong>：支持 主流平台同时安全运营多个账号。</li><li><strong>双内核</strong>：提供基于 Chromium 和 Firefox 的两种浏览器，灵活适配不同需求。</li><li><strong>RPA 自动化</strong>：无需编程即可录制和批量执行操作，大幅提升工作效率。</li><li><strong>团队协作</strong>：支持权限管理和操作日志，适合多人团队使用。</li><li><strong>价格亲民</strong>：有免费版支持两个浏览器环境，超过两个需要支持月费。</li></ol><p>总体来说，AdsPower 适合跨境电商、社媒营销、数据采集等需要<strong>多账号管理 + 隐私保护</strong>的用户，是目前市场上功能较全面、价格较实惠的同类工具之一。</p><p><a href="https://www.adspower.net/share/aehyok" target="_blank" rel="noreferrer">https://www.adspower.net/share/aehyok</a> 打开官网链接右上角下载对应的版本即可。</p><p>登录完毕之后看到如下界面</p><p><img src="https://pbs.twimg.com/media/HFjT44paoAA5TL2?format=jpg&amp;name=large" alt="图像"></p><p>点击左上角「新建浏览器」,输入「名称」</p><p><img src="https://pbs.twimg.com/media/HFjkk5TakAYFvzb?format=jpg&amp;name=large" alt="图像"></p><p>再点击「代理信息」，直接使用默认的直连，也就是使用本机电脑的网络就可以了。</p><p>然后再点击「指纹配置」的硬件噪音进行全部勾选。</p><p>点击下面「确定」即配置完毕，会看到一条记录。</p><p><img src="https://pbs.twimg.com/media/HFjl98daYAALVW3?format=jpg&amp;name=large" alt="图像"></p><p>点击「打开」会先进行下载我们先前配置的SubBrowser</p><p><img src="https://pbs.twimg.com/media/HFjnMbKakAUnLCH?format=jpg&amp;name=large" alt="图像"></p><p>下载完毕再「打开」就打开AdsPower 提供的浏览器</p><p><img src="https://pbs.twimg.com/media/HFq8wFuaIAAiMoy?format=jpg&amp;name=large" alt="图像"></p><p>新开个标签就可以输入claude官网进行下面的步骤了。</p><h2 id="四、注册邮箱-接码平台" tabindex="-1">四、注册邮箱+接码平台 <a class="header-anchor" href="#四、注册邮箱-接码平台" aria-label="Permalink to &quot;四、注册邮箱+接码平台&quot;">​</a></h2><p>一般情况下，如果「2、网络环境」准备充分，可能直接不需要接码平台了。但偶尔还是一样会触发手机验证码的，所以我也没用之前注册过账号的浏览器了。同样这里没有使用比如giffgaff卡或者其他同类国外卡了，被封后用处就不大了，如果直接被秒封其实成本也是有一些的，如果你钱多，那我还是建议尽量不要用接码平台。</p><p>具体的注册Claude账号流程如下面这篇文章</p><blockquote><p>4月5日</p></blockquote><h2 id="五、支付-bitget银行卡-apple-pay或者google-pay" tabindex="-1">五、支付：Bitget银行卡+Apple Pay或者Google Pay <a class="header-anchor" href="#五、支付-bitget银行卡-apple-pay或者google-pay" aria-label="Permalink to &quot;五、支付：Bitget银行卡+Apple Pay或者Google Pay&quot;">​</a></h2><p>最近也看到很多使用Apple Pay的被封的蛮多，于是我这里准备绑定Google Pay。我的Bitget U卡去年10月25日开通的，看截图目前我只用来消费X会员充值、以及在Spaceship上购买过域名，使用过程非常丝滑。</p><p><img src="https://pbs.twimg.com/media/HFsfoR6a4AAfSdc?format=jpg&amp;name=large" alt="图像"></p><p>当时主要是觉得免年费，而且每月消费低于400U没有手续费（我看还有600U 800U的），可以绑定微信支付宝，好像充值是有一点磨损的不过也无所谓了，尽量还是保持用多少充多少的习惯，稍微留一点，不要流多了。</p><p>有兴趣的可以点击链接进行申请 <a href="https://web3.bitget.com/share/3vQ3Eh?inviteCode=p6Apyx" target="_blank" rel="noreferrer">https://web3.bitget.com/share/3vQ3Eh?inviteCode=p6Apyx</a></p><p>如果你是直接下载的 App，开卡后记得点进「邀请」页面，输入我的专属邀请码：<a href="https://web3.bitget.com/share/3vQ3Eh?inviteCode=p6Apyx" target="_blank" rel="noreferrer">p6Apyx</a></p><p>注册全过程可以参考这篇文章，非常详细，你也可以直接使用她的邀请码</p><blockquote><p>3月31日</p></blockquote><p>这里我其实我也早已绑定了Google Pay，使用的就是上面的的Bitget，就是要等待合适的时机再尝试一次了。</p><p><img src="https://pbs.twimg.com/media/HFsiJjEawAAvxAd?format=jpg&amp;name=large" alt="图像"></p><h2 id="六、最后" tabindex="-1">六、最后 <a class="header-anchor" href="#六、最后" aria-label="Permalink to &quot;六、最后&quot;">​</a></h2><p>伙伴们，你还有什么妙招？快拿出来，让大家试试看。</p>',50)]))}const c=e(o,[["render",s]]);export{h as __pageData,c as default};
